def adv_encode_name(name):
    """Encodes the device name for the advertising payload."""
    return b'\x09\x09' + name.encode('utf-8') # AD Type 0x09: Complete Local Name

def adv_encode_uuid(uuid):
    """Encodes a UUID for the advertising payload (16-bit or 128-bit)."""
    b = uuid.bytes
    # 0x03 for 16-bit Service UUID, 0x07 for 128-bit Service UUID
