    ble.irq(ble_irq) # Register the event handler

    # Define the GATT services and their characteristics
    # Characteristic definition format: (UUID, properties, optional_permissions)
    # Properties: ubluetooth.FLAG_READ, ubluetooth.FLAG_WRITE, ubluetooth.FLAG_NOTIFY, etc.
    # Permissions: ubluetooth.AUTH_READ, ubluetooth.AUTH_WRITE (requires authentication/bonding)

